package courses

import (
	"context"
	"fmt"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type CourseService struct {
	queries *db.Queries
}

func NewCourseService(queries *db.Queries) *CourseService {
	return &CourseService{queries: queries}
}

type GetCoursesResult struct {
	Courses    []db.GerCoursesRow
	NextCursor string
}

func (s *CourseService) GetCourses(ctx context.Context, cursor string, limit int) (GetCoursesResult, error) {
	var cursorUUID pgtype.UUID
	if cursor == "" {
		cursorUUID = pgtype.UUID{Bytes: [16]byte{}, Valid: true}
	} else {
		if err := cursorUUID.Scan(cursor); err != nil {
			return GetCoursesResult{}, err
		}
	}

	rows, err := s.queries.GerCourses(ctx, db.GerCoursesParams{
		CourseID: cursorUUID,
		Column2:  limit,
	})
	if err != nil {
		return GetCoursesResult{}, err
	}

	var nextCursor string
	if len(rows) > limit {
		rows = rows[:limit]
		b := rows[len(rows)-1].CourseID.Bytes
		nextCursor = fmt.Sprintf("%08x-%04x-%04x-%04x-%012x", b[0:4], b[4:6], b[6:8], b[8:10], b[10:16])
	}

	return GetCoursesResult{
		Courses:    rows,
		NextCursor: nextCursor,
	}, nil
}

